import (
	"fmt"
	"sync"
)

func main() {
	var mutex sync.Mutex
	count := 0
	var group sync.WaitGroup
	for worker := 0; worker < 5; worker++ {
		group.Add(1)
		go func() { defer group.Done(); mutex.Lock(); count++; mutex.Unlock() }()
	}
	group.Wait()
	fmt.Println(count)
}

